class Solution {
public:
    long long validSubstringCount(string word1, string word2) {
        int n = word1.size(), m = word2.size();
        vector<int> count(26, 0), target(26, 0);
        for (char c : word2) target[c - 'a']++;
        long long res = 0;
        int left = 0, formed = 0;
        for (int right = 0; right < n; ++right) {
            count[word1[right] - 'a']++;
            if (count[word1[right] - 'a'] == target[word1[right] - 'a']) formed++;
            while (formed == target.size() && left <= right) {
                count[word1[left] - 'a']--;
                if (count[word1[left] - 'a'] < target[word1[left] - 'a']) formed--;
                res += n - right;
                left++;
            }
        }
        return res;
    }
};
efficiency: HIGH
time complexity: O(N)
